INSERT INTO proposals (id, project_id, quotation_id, title, status, executive_summary, scope_of_work, design_approach, material_specifications, timeline_phases, terms_and_conditions, payment_schedule, ai_generated, ai_model_used, public_token, sent_at, created_at, updated_at) VALUES (1, 2, 5, 'Interior Design Proposal 2 BHK', 'draft', 'We are pleased to present this interior design proposal for 2 BHK Aprtment - Muralidharan for MURALIDHARAN. Our team will transform your space with thoughtful design, quality materials, and expert craftsmanship. This proposal covers the complete interior design and execution for Room MB, Room GB, Kitchen, Pooja Unit.', 'The scope of work includes design, material procurement, and execution for: Room MB, Room GB, Kitchen, Pooja Unit. Work includes civil modifications, false ceiling, flooring, painting, electrical work, carpentry, and furnishing as detailed in the accompanying quotation.', 'Our design approach combines contemporary aesthetics with functional space planning. We focus on creating harmonious living spaces that reflect your lifestyle and preferences, using a carefully curated palette of materials and finishes.', 'All materials used will be of premium quality sourced from reputed brands. Plywood: BWP grade (Greenply/Century). Hardware: Hettich/Hafele soft-close fittings. Paints: Asian Paints Royale range. Tiles: Kajaria/Somany. Laminates: Merino/Greenlam.', 'Phase 1: Design Development (1-2 weeks)
INSERT INTO proposals (id, project_id, quotation_id, title, status, executive_summary, scope_of_work, design_approach, material_specifications, timeline_phases, terms_and_conditions, payment_schedule, ai_generated, ai_model_used, public_token, sent_at, created_at, updated_at) VALUES (2, 2, 5, 'Interior Design proposal - Muralidharan ', 'draft', 'நாங்கள் இந்த உட்புற வடிவமைப்பு முன்மொழிவை 2 BHK அபார்ட்மெண்ட் - முரளிதரன் அவர்களுக்கு வழங்கவதில் மகிழ்ச்சியடைகிறோம். முரளிதரன். எங்கள் குழு உங்கள் இடத்தை சிந்தனைமிக்க வடிவமைப்பு, தரமான பொருட்கள் மற்றும் நிபுணத்துவ கைவினைத்திறனுடன் மாற்றியமைக்கும். இந்த முன்மொழிவு ரூம் எம்பி, ரூம் ஜிபி, சமையலறை, போஜ்யா அலமாரி ஆகியவற்றுக்கான முழுமையான உட்புற வடிவமைப்பு மற்றும் செயல்பாட்டையும் உள்ளடக்கியது.', 'வேலைக்கான வரம்பு வடிவமைப்பை உள்ளடக்கியது, பொருட்கள் கொள்முதல் மற்றும் செயல்படுத்தல் ஆகியவை பின்வருமாறு: அறை எம்.பி, அறை ஜி.பி, சமையலறை, போஜ்யா அலமாரி. வேலைகளில் சிவில் மாற்றங்கள், பொய்மை கூரை, தரைவிரிப்பு, பெயிண்டிங், மின்சார வேலை, மரவேலை மற்றும் இணைக்கப்பட்டுள்ள மேற்கோளின்படி தளபாடங்கள் ஆகியவை அடங்கும்.', 'எங்கள் வடிவமைப்பு அணுகுமுறை நவீன அழகியல் மற்றும் செயல்பாட்டு இட திட்டமிடலுடன் இணைக்கப்பட்டுள்ளது. உங்கள் வாழ்க்கை முறை மற்றும் விருப்பங்களைப் பிரதிபலிக்கும் இணக்கமான வாழ்க்கை இடங்களை உருவாக்குவதில் நாங்கள் கவனம் செலுத்துகிறோம். கவனமாகத் தேர்ந்தெடுக்கப்பட்ட பொருட்களின் மற்றும் பூரணிகளின் கலையைப் பயன்படுத்துகிறோம்.', 'எடுக்கப்படும் அனைத்து பொருட்களும் புகழ்பெற்ற பிராண்டுகளிலிருந்து பெறப்பட்ட உயர்தர பொருட்களால் செய்யப்பட்டிருக்கும். மரம்: BWP தர (Greenply/Century). வன்பொருள்: Hettich/Hafele மென்மையான மூடுதலுக்கான பாகங்கள். வண்ணப்பூச்சுகள்: Asian Paints Royale வரிசை. டைல்ஸ்: Kajaria/Somany. லமினேட்: Merino/Greenlam.', 'Phase 1: வடிவமைப்பு உருவாக்கம் (1-2 வாரங்கள்)
